struct PaymentDemoView: View {
    @Environment(\.dismiss) private var dismiss
    @Binding var resultText: String
    @StateObject private var model = PaymentDemoModel()

    var body: some View {
        NavigationView {
            VStack(spacing: 24) {
                Text("Stripe Payment Demo")
                    .font(.title2)
                    .bold()

                Text("This demo uses a backend-provided PaymentIntent client secret.")
                    .multilineTextAlignment(.center)
                    .foregroundColor(.secondary)
                    .padding(.horizontal)

                Button("Load Payment Sheet") {
                    model.preparePaymentSheet()
                }
                .buttonStyle(.bordered)

                if model.isLoading {
                    ProgressView()
                }

                if let paymentSheet = model.paymentSheet {
                    PaymentSheetButton(paymentSheet: paymentSheet) { result in
                        switch result {
                        case .completed:
                            resultText = "Payment completed"
                        case .canceled:
                            resultText = "Payment canceled"
                        case .failed(let error):
                            resultText = "Payment failed: \(error.localizedDescription)"
                        }
                        dismiss()
                    }
                }

                if let message = model.statusMessage {
                    Text(message)
                        .font(.footnote)
                        .multilineTextAlignment(.center)
                        .foregroundColor(.secondary)
                        .padding(.horizontal)
                }

                Spacer()
            }
            .padding()
            .navigationTitle("Payment")
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Close") {
                        dismiss()
                    }
                }
            }
        }
    }
}

final class PaymentDemoModel: ObservableObject {
    @Published var paymentSheet: PaymentSheet?
    @Published var isLoading = false
    @Published var statusMessage: String?

    func preparePaymentSheet() {
        isLoading = true
        statusMessage = nil

        let config = PaymentSheet.Configuration()
        var mutableConfig = config
        mutableConfig.merchantDisplayName = "Investor Demo"

        let clientSecret = ProcessInfo.processInfo.environment["STRIPE_PAYMENT_INTENT_CLIENT_SECRET"] ?? ""

        guard !clientSecret.isEmpty else {
            isLoading = false
            statusMessage = "Missing STRIPE_PAYMENT_INTENT_CLIENT_SECRET environment value."
            return
        }

        paymentSheet = PaymentSheet(paymentIntentClientSecret: clientSecret, configuration: mutableConfig)
        isLoading = false
        statusMessage = "Payment Sheet ready."
    }
}

struct PaymentSheetButton: View {
    let paymentSheet: PaymentSheet
    let onCompletion: (PaymentSheetResult) -> Void

    @State private var paymentSheetPresented = false

    var body: some View {
        Button("Present Payment Sheet") {
            paymentSheetPresented = true
        }
        .buttonStyle(.borderedProminent)
        .paymentSheet(isPresented: $paymentSheetPresented, paymentSheet: paymentSheet, onCompletion: onCompletion)
    }
}